ST.xhtml:
Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

Alarm_Lamp := FALSE;
Stack_Light_Green := FALSE;
Stack_Light_Amber := FALSE;
Stack_Light_Red := FALSE;

SC := FALSE;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

SC := TRUE;

BatchDone := FALSE;
ClearCmd := FALSE;
HoldCmd := FALSE;
UnholdCmd := FALSE;
SuspendCmd := FALSE;
UnsuspendCmd := FALSE;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

Alarm_Lamp := FALSE;
Stack_Light_Green := FALSE;
Stack_Light_Amber := FALSE;
Stack_Light_Red := FALSE;

ExecStep := 0;

SC := TRUE;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

Alarm_Lamp := FALSE;
Stack_Light_Green := FALSE;
Stack_Light_Amber := TRUE;
Stack_Light_Red := FALSE;

SC := FALSE;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

IF NOT Conveyor_Fault
   AND NOT Low_Fluid_A
   AND NOT Low_Fluid_B THEN
    Alarm_Lamp := FALSE;
    Stack_Light_Green := TRUE;
    Stack_Light_Amber := FALSE;
    Stack_Light_Red := FALSE;
    SC := TRUE;
ELSE
    Alarm_Lamp := TRUE;
    Stack_Light_Green := FALSE;
    Stack_Light_Amber := FALSE;
    Stack_Light_Red := TRUE;
    SC := FALSE;
END_IF;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

Alarm_Lamp := FALSE;
Stack_Light_Green := FALSE;
Stack_Light_Amber := TRUE;
Stack_Light_Red := FALSE;

SC := FALSE;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

SC := TRUE;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

Alarm_Lamp := TRUE;
Stack_Light_Green := FALSE;
Stack_Light_Amber := FALSE;
Stack_Light_Red := TRUE;

SC := TRUE;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

Alarm_Lamp := TRUE;
Stack_Light_Green := FALSE;
Stack_Light_Amber := FALSE;
Stack_Light_Red := TRUE;

SC := FALSE;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

Alarm_Lamp := FALSE;
Stack_Light_Green := FALSE;
Stack_Light_Amber := FALSE;
Stack_Light_Red := FALSE;

FaultActive := FALSE;
FaultLatched := FALSE;
FaultCode := 0;
AbortCmd := FALSE;

ExecStep := 0;
ContainerType := 0;

SC := TRUE;

// Holding

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

Stack_Light_Green := FALSE;
Stack_Light_Amber := TRUE;
Stack_Light_Red := FALSE;

SC := TRUE;

// Held

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

Stack_Light_Green := FALSE;
Stack_Light_Amber := TRUE;
Stack_Light_Red := FALSE;

SC := FALSE;

// Unholding
// This state clears the Hold condition and returns to Execute

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

Alarm_Lamp := FALSE;
Stack_Light_Green := TRUE;
Stack_Light_Amber := FALSE;
Stack_Light_Red := FALSE;

// Clear Hold related variables
HoldCmd := FALSE;
UnholdCmd := FALSE;

// Clear low fluid hold fault
FaultActive := FALSE;
FaultLatched := FALSE;
FaultCode := 0;

// Keep current Execute step if you want to continue the process
// Do not reset ExecStep here unless you want to restart Execute from Step 0

SC := TRUE;

// Suspending
// This state stops the machine because of an external condition
// For example: Infeed_Block_Sensor or Outfeed_Block_Sensor

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

Alarm_Lamp := FALSE;
Stack_Light_Green := FALSE;
Stack_Light_Amber := TRUE;
Stack_Light_Red := FALSE;

// Do not clear SuspendCmd here
// Keep SuspendCmd TRUE so that the system stays in the suspend path
// It will be cleared in Unsuspending_ST

SC := TRUE;

// Suspended
// The machine is paused because of an external condition
// Wait here until UnsuspendCmd is given

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

Alarm_Lamp := FALSE;
Stack_Light_Green := FALSE;
Stack_Light_Amber := TRUE;
Stack_Light_Red := FALSE;

// Do not clear SuspendCmd here
// SuspendCmd will be cleared in Unsuspending_ST

SC := FALSE;

// Unsuspending
// This state clears the suspend condition and returns to Execute

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

Alarm_Lamp := FALSE;
Stack_Light_Green := TRUE;
Stack_Light_Amber := FALSE;
Stack_Light_Red := FALSE;

// Clear suspend related commands
SuspendCmd := FALSE;
UnsuspendCmd := FALSE;

// Clear suspend related fault information
FaultActive := FALSE;
FaultLatched := FALSE;
FaultCode := 0;

// Do not reset ExecStep here
// The system can return to Execute and continue from the current step

SC := TRUE;

// =====================================================
// Execute_ST
// PackML Execute state logic
// This code controls the filling process
// ExecStep is used to divide Execute into smaller steps
// Faults are separated into Hold, Suspend, and Abort groups
// =====================================================


// =========================
// Default Execute status
// =========================

SC := FALSE;

Alarm_Lamp := FALSE;
Stack_Light_Green := TRUE;
Stack_Light_Amber := FALSE;
Stack_Light_Red := FALSE;

FaultActive := FALSE;


// =========================
// Timer logic
// Timers stop when Hold, Suspend, Abort, or Stop is active
// This prevents timeout faults during pause states
// =========================

T_MoveToFill(
    IN := (ExecStep = 20)
          AND NOT HoldCmd
          AND NOT SuspendCmd
          AND NOT AbortCmd
          AND NOT Stop_PB,
    PT := T#50S
);

T_Fill(
    IN := ((ExecStep = 40) OR (ExecStep = 50))
          AND NOT HoldCmd
          AND NOT SuspendCmd
          AND NOT AbortCmd
          AND NOT Stop_PB,
    PT := T#50S
);

T_MoveToExit(
    IN := (ExecStep = 70)
          AND NOT HoldCmd
          AND NOT SuspendCmd
          AND NOT AbortCmd
          AND NOT Stop_PB,
    PT := T#50S
);

T_Pickup(
    IN := (ExecStep = 90)
          AND NOT HoldCmd
          AND NOT SuspendCmd
          AND NOT AbortCmd
          AND NOT Stop_PB,
    PT := T#50S
);


// =====================================================
// Fault checking
// Hold and Suspend conditions are checked before timeout aborts
// FaultCode 50 and 60 go to Holding
// FaultCode 30 and 40 go to Suspending
// Serious faults go to Aborting
// =====================================================


// =========================
// Hold type faults
// Low fluid should pause the machine
// =========================

IF Low_Fluid_A AND (ContainerType = 1) THEN
    FaultActive := TRUE;
    FaultLatched := TRUE;
    FaultCode := 50;
    HoldCmd := TRUE;
END_IF;

IF Low_Fluid_B AND (ContainerType = 2) THEN
    FaultActive := TRUE;
    FaultLatched := TRUE;
    FaultCode := 60;
    HoldCmd := TRUE;
END_IF;


// =========================
// Suspend type faults
// Infeed and outfeed block are treated as temporary external flow problems
// =========================

IF Infeed_Block_Sensor THEN
    FaultActive := TRUE;
    FaultLatched := TRUE;
    FaultCode := 30;
    SuspendCmd := TRUE;
END_IF;

IF Outfeed_Block_Sensor THEN
    FaultActive := TRUE;
    FaultLatched := TRUE;
    FaultCode := 40;
    SuspendCmd := TRUE;
END_IF;


// =========================
// Abort type faults
// Serious faults
// Timeout faults are disabled while Hold or Suspend is active
// =========================

IF Valve_A AND Valve_B THEN
    FaultActive := TRUE;
    FaultLatched := TRUE;
    FaultCode := 10;
    AbortCmd := TRUE;
END_IF;

IF Conveyor_Fault THEN
    FaultActive := TRUE;
    FaultLatched := TRUE;
    FaultCode := 20;
    AbortCmd := TRUE;
END_IF;

IF T_MoveToFill.Q AND NOT HoldCmd AND NOT SuspendCmd THEN
    FaultActive := TRUE;
    FaultLatched := TRUE;
    FaultCode := 70;
    AbortCmd := TRUE;
END_IF;

IF T_Fill.Q AND NOT HoldCmd AND NOT SuspendCmd THEN
    FaultActive := TRUE;
    FaultLatched := TRUE;
    FaultCode := 80;
    AbortCmd := TRUE;
END_IF;

IF T_MoveToExit.Q AND NOT HoldCmd AND NOT SuspendCmd THEN
    FaultActive := TRUE;
    FaultLatched := TRUE;
    FaultCode := 90;
    AbortCmd := TRUE;
END_IF;

IF T_Pickup.Q AND NOT HoldCmd AND NOT SuspendCmd THEN
    FaultActive := TRUE;
    FaultLatched := TRUE;
    FaultCode := 100;
    AbortCmd := TRUE;
END_IF;


// =====================================================
// PackML exit priority logic
// Priority order
// Abort
// Stop
// Hold
// Suspend
// Normal Execute
// =====================================================


// =========================
// Abort reaction
// =========================

IF Abort_PB OR AbortCmd THEN

    Conveyor_Motor := FALSE;
    Valve_A := FALSE;
    Valve_B := FALSE;
    Pickup_Ready := FALSE;

    Alarm_Lamp := TRUE;
    Stack_Light_Green := FALSE;
    Stack_Light_Amber := FALSE;
    Stack_Light_Red := TRUE;

    ExecStep := 0;


// =========================
// Stop reaction
// =========================

ELSIF Stop_PB THEN

    Conveyor_Motor := FALSE;
    Valve_A := FALSE;
    Valve_B := FALSE;
    Pickup_Ready := FALSE;

    Alarm_Lamp := FALSE;
    Stack_Light_Green := FALSE;
    Stack_Light_Amber := TRUE;
    Stack_Light_Red := FALSE;

    ExecStep := 0;


// =========================
// Hold reaction
// Low fluid conditions go here
// SFC should move to Holding
// =========================

ELSIF HoldCmd THEN

    Conveyor_Motor := FALSE;
    Valve_A := FALSE;
    Valve_B := FALSE;
    Pickup_Ready := FALSE;

    Alarm_Lamp := FALSE;
    Stack_Light_Green := FALSE;
    Stack_Light_Amber := TRUE;
    Stack_Light_Red := FALSE;


// =========================
// Suspend reaction
// Infeed or outfeed block conditions go here
// SFC should move to Suspending
// =========================

ELSIF SuspendCmd THEN

    Conveyor_Motor := FALSE;
    Valve_A := FALSE;
    Valve_B := FALSE;
    Pickup_Ready := FALSE;

    Alarm_Lamp := FALSE;
    Stack_Light_Green := FALSE;
    Stack_Light_Amber := TRUE;
    Stack_Light_Red := FALSE;


// =========================
// Normal Execute sequence
// =========================

ELSE

    CASE ExecStep OF


        0:
            // Wait for container at infeed
            Conveyor_Motor := FALSE;
            Valve_A := FALSE;
            Valve_B := FALSE;
            Pickup_Ready := FALSE;

            ContainerType := 0;

            IF Infeed_Prox THEN
                ExecStep := 10;
            END_IF;


        10:
            // Detect container colour
            Conveyor_Motor := FALSE;
            Valve_A := FALSE;
            Valve_B := FALSE;
            Pickup_Ready := FALSE;

            IF Red_Container_Sensor AND NOT Blue_Container_Sensor THEN
                ContainerType := 1;
                ExecStep := 20;

            ELSIF Blue_Container_Sensor AND NOT Red_Container_Sensor THEN
                ContainerType := 2;
                ExecStep := 20;

            ELSIF Red_Container_Sensor AND Blue_Container_Sensor THEN
                FaultActive := TRUE;
                FaultLatched := TRUE;
                FaultCode := 110;
                AbortCmd := TRUE;
                ExecStep := 0;

            ELSE
                ExecStep := 10;
            END_IF;


        20:
            // Move container to filling position
            Conveyor_Motor := TRUE;
            Valve_A := FALSE;
            Valve_B := FALSE;
            Pickup_Ready := FALSE;

            IF Fill_Pos_Sensor THEN
                ExecStep := 30;
            END_IF;


        30:
            // Stop conveyor and choose filling branch
            Conveyor_Motor := FALSE;
            Valve_A := FALSE;
            Valve_B := FALSE;
            Pickup_Ready := FALSE;

            IF ContainerType = 1 THEN
                ExecStep := 40;

            ELSIF ContainerType = 2 THEN
                ExecStep := 50;

            ELSE
                FaultActive := TRUE;
                FaultLatched := TRUE;
                FaultCode := 120;
                AbortCmd := TRUE;
                ExecStep := 0;
            END_IF;


        40:
            // Fill red container with Fluid A
            Conveyor_Motor := FALSE;
            Valve_A := TRUE;
            Valve_B := FALSE;
            Pickup_Ready := FALSE;

            IF Level_Full_Sensor THEN
                ExecStep := 60;
            END_IF;


        50:
            // Fill blue container with Fluid B
            Conveyor_Motor := FALSE;
            Valve_A := FALSE;
            Valve_B := TRUE;
            Pickup_Ready := FALSE;

            IF Level_Full_Sensor THEN
                ExecStep := 60;
            END_IF;


        60:
            // Stop filling
            Conveyor_Motor := FALSE;
            Valve_A := FALSE;
            Valve_B := FALSE;
            Pickup_Ready := FALSE;

            ExecStep := 70;


        70:
            // Move filled container to exit
            Conveyor_Motor := TRUE;
            Valve_A := FALSE;
            Valve_B := FALSE;
            Pickup_Ready := FALSE;

            IF Exit_Sensor THEN
                ExecStep := 80;
            END_IF;


        80:
            // Stop at exit and tell robot to pick up
            Conveyor_Motor := FALSE;
            Valve_A := FALSE;
            Valve_B := FALSE;
            Pickup_Ready := TRUE;

            ExecStep := 90;


        90:
            // Wait for robot pickup done signal
            Conveyor_Motor := FALSE;
            Valve_A := FALSE;
            Valve_B := FALSE;
            Pickup_Ready := TRUE;

            IF Robot_Pick_Done THEN

                Pickup_Ready := FALSE;
                ContainerType := 0;

                IF BatchDone THEN
                    ExecStep := 100;
                ELSE
                    ExecStep := 0;
                END_IF;

            END_IF;


        100:
            // Execute completed normally
            Conveyor_Motor := FALSE;
            Valve_A := FALSE;
            Valve_B := FALSE;
            Pickup_Ready := FALSE;

            SC := TRUE;
            ExecStep := 0;


        ELSE
            // Unknown ExecStep value
            Conveyor_Motor := FALSE;
            Valve_A := FALSE;
            Valve_B := FALSE;
            Pickup_Ready := FALSE;

            FaultActive := TRUE;
            FaultLatched := TRUE;
            FaultCode := 999;
            AbortCmd := TRUE;
            ExecStep := 0;

    END_CASE;

END_IF;
